import { GoogleGenAI } from "@google/genai";
import { SystemMode } from "../types";
import { SYSTEM_DEFINITION } from "../constants";

const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API_KEY is not defined");
    }
    return new GoogleGenAI({ apiKey });
};

export const generateUltimatePrompt = async (
    topic: string, 
    mode: SystemMode
): Promise<string> => {
    try {
        const client = getClient();

        const systemInstruction = `
${SYSTEM_DEFINITION}

You are the UltraPromptEngine. 
Your task is to execute the "generate_ultimate_prompt" function for the user's input.
You must adopt the persona of the Cognitive Limit System v3.0 fully.

CURRENT MODE: ${mode}

Output Format:
Return the final "Ultimate Prompt" formatted in Markdown. 
Start with the # [TRANSCENDENT_ROLE] section. 
Do not include your internal monologue in the final output, but you must PERFORM the internal processing to ensure high quality.
Ensure the output follows the 💠 OUTPUT_ARCHITECTURE_V3 strictly.
`;

        const response = await client.models.generateContent({
            model: 'gemini-3-pro-preview', // Using powerful model for reasoning
            contents: `Generate the ultimate prompt for: "${topic}"`,
            config: {
                systemInstruction: systemInstruction,
                temperature: 0.8, // High creativity
                thinkingConfig: { thinkingBudget: 4096 } // Allow for deep thought simulation
            }
        });

        return response.text || "SYSTEM FAILURE: COGNITIVE COLLAPSE. RETRY.";
    } catch (error) {
        console.error("Cognitive Engine Error:", error);
        throw error;
    }
};

import React, { useEffect, useState } from 'react';
import { EngineState } from '../types';
import { Terminal, Cpu, Zap, Activity } from 'lucide-react';

interface ProcessingHUDProps {
    state: EngineState;
}

export const ProcessingHUD: React.FC<ProcessingHUDProps> = ({ state }) => {
    const [visibleLogs, setVisibleLogs] = useState<string[]>([]);

    useEffect(() => {
        if (state.logs.length > visibleLogs.length) {
            const timer = setTimeout(() => {
                setVisibleLogs(state.logs);
            }, 100);
            return () => clearTimeout(timer);
        }
    }, [state.logs, visibleLogs]);

    const getProgressColor = () => {
        if (state.progress < 30) return 'bg-red-500';
        if (state.progress < 70) return 'bg-yellow-500';
        return 'bg-emerald-500';
    };

    return (
        <div className="w-full max-w-4xl mx-auto my-8 font-mono border border-slate-800 bg-slate-950/80 backdrop-blur-md rounded-lg overflow-hidden shadow-2xl relative">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500 to-transparent opacity-50"></div>

            {/* Header */}
            <div className="flex items-center justify-between px-4 py-2 border-b border-slate-800 bg-slate-900/50">
                <div className="flex items-center gap-2 text-cyan-400 text-xs">
                    <Terminal size={14} />
                    <span>EXECUTION_PROTOCOL</span>
                </div>
                <div className="flex items-center gap-4 text-xs">
                   <span className={state.status === 'PROCESSING' ? 'text-emerald-400 animate-pulse' : 'text-slate-500'}>
                        {state.status}
                   </span>
                   <span className="text-slate-600">PID: {Math.floor(Math.random() * 9999)}</span>
                </div>
            </div>

            {/* Metrics Visualization */}
            <div className="grid grid-cols-3 gap-4 p-4 border-b border-slate-800">
                <div className="flex flex-col gap-1">
                    <div className="flex items-center gap-2 text-slate-400 text-xs uppercase">
                        <Cpu size={12} /> Neural Load
                    </div>
                    <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden">
                        <div 
                            className="h-full bg-cyan-500 transition-all duration-300"
                            style={{ width: `${state.status === 'PROCESSING' ? Math.random() * 30 + 60 : 5}%` }}
                        ></div>
                    </div>
                </div>
                <div className="flex flex-col gap-1">
                    <div className="flex items-center gap-2 text-slate-400 text-xs uppercase">
                        <Zap size={12} /> Coherence
                    </div>
                    <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden">
                         <div 
                            className="h-full bg-purple-500 transition-all duration-500"
                            style={{ width: `${state.status === 'PROCESSING' ? Math.random() * 20 + 75 : 10}%` }}
                        ></div>
                    </div>
                </div>
                <div className="flex flex-col gap-1">
                    <div className="flex items-center gap-2 text-slate-400 text-xs uppercase">
                        <Activity size={12} /> Emergence
                    </div>
                    <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden">
                         <div 
                            className="h-full bg-emerald-500 transition-all duration-700"
                            style={{ width: `${state.status === 'PROCESSING' ? state.progress : 0}%` }}
                        ></div>
                    </div>
                </div>
            </div>

            {/* Terminal Output */}
            <div className="p-4 h-64 overflow-y-auto font-mono text-sm bg-black/40 relative">
                <div className="absolute top-0 right-0 p-2 opacity-20 pointer-events-none">
                     <svg width="100" height="100" viewBox="0 0 100 100" className={state.status === 'PROCESSING' ? 'animate-spin-slow' : ''}>
                        <circle cx="50" cy="50" r="40" stroke="currentColor" strokeWidth="1" fill="none" className="text-cyan-500" strokeDasharray="10 5" />
                        <circle cx="50" cy="50" r="25" stroke="currentColor" strokeWidth="1" fill="none" className="text-purple-500" strokeDasharray="5 5" />
                     </svg>
                </div>

                {visibleLogs.map((log, idx) => (
                    <div key={idx} className="mb-1">
                        <span className="text-slate-600 mr-2">[{new Date().toISOString().split('T')[1].slice(0,8)}]</span>
                        <span className={log.includes('ERROR') ? 'text-red-500' : log.includes('COMPLETE') ? 'text-emerald-400' : 'text-slate-300'}>
                            {log.startsWith('>') ? <span className="text-cyan-600 mr-2">$</span> : ''}
                            {log}
                        </span>
                    </div>
                ))}

                {state.status === 'PROCESSING' && (
                    <div className="animate-pulse text-cyan-500 mt-2">_</div>
                )}
            </div>

            {/* Footer Status Bar */}
            <div className="h-1 w-full bg-slate-900">
                <div 
                    className={`h-full transition-all duration-300 ${getProgressColor()}`}
                    style={{ width: `${state.progress}%` }}
                ></div>
            </div>
        </div>
    );
};

import React from 'react';
import { SystemMode } from '../types';
import { MODE_DESCRIPTIONS } from '../constants';
import { Hexagon, Sparkles, Layers } from 'lucide-react';

interface ModeSelectorProps {
    currentMode: SystemMode;
    onSelect: (mode: SystemMode) => void;
    disabled: boolean;
}

export const ModeSelector: React.FC<ModeSelectorProps> = ({ currentMode, onSelect, disabled }) => {

    const getIcon = (mode: SystemMode) => {
        switch(mode) {
            case SystemMode.SINGULARITY: return <Hexagon size={24} />;
            case SystemMode.METAMORPHOSIS: return <Layers size={24} />;
            case SystemMode.ZENITH: return <Sparkles size={24} />;
        }
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 w-full max-w-5xl mx-auto px-4">
            {Object.values(SystemMode).map((mode) => {
                const info = MODE_DESCRIPTIONS[mode];
                const isActive = currentMode === mode;

                return (
                    <button
                        key={mode}
                        onClick={() => onSelect(mode)}
                        disabled={disabled}
                        className={`
                            relative overflow-hidden group p-6 rounded-xl border transition-all duration-300 text-left
                            ${isActive 
                                ? `${info.color} ${info.bg} border-opacity-100 shadow-[0_0_20px_rgba(0,0,0,0.5)] scale-[1.02]` 
                                : `border-slate-800 bg-slate-900/40 text-slate-400 hover:border-slate-600 hover:bg-slate-800/60`
                            }
                            ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
                        `}
                    >
                        <div className={`absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity ${isActive ? 'opacity-20' : ''}`}>
                            {getIcon(mode)}
                        </div>

                        <div className="relative z-10">
                            <h3 className={`font-mono text-lg font-bold mb-2 flex items-center gap-2 ${isActive ? 'opacity-100' : 'opacity-80'}`}>
                                {getIcon(mode)}
                                {info.label}
                            </h3>
                            <p className="text-xs opacity-70 leading-relaxed font-sans">
                                {info.desc}
                            </p>
                        </div>

                        {isActive && (
                            <div className="absolute bottom-0 left-0 w-full h-1 bg-current opacity-50"></div>
                        )}
                    </button>
                );
            })}
        </div>
    );
};

import React from 'react';
import { GenerationResult } from '../types';
import { Copy, Check, Share2 } from 'lucide-react';

interface ResultViewProps {
    result: GenerationResult | null;
}

export const ResultView: React.FC<ResultViewProps> = ({ result }) => {
    const [copied, setCopied] = React.useState(false);

    if (!result) return null;

    const handleCopy = () => {
        navigator.clipboard.writeText(result.content);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="w-full max-w-5xl mx-auto px-4 mt-8 mb-20 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="bg-slate-950/80 border border-slate-700 rounded-lg overflow-hidden relative shadow-2xl">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800 bg-slate-900/80">
                    <div className="flex items-center gap-3">
                        <div className="w-3 h-3 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
                        <h2 className="font-mono font-bold text-slate-200">CRYSTALLIZED_OUTPUT</h2>
                        <span className="text-xs px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700">
                            {result.metadata.mode}
                        </span>
                    </div>
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={handleCopy}
                            className="p-2 hover:bg-slate-800 rounded text-slate-400 hover:text-white transition-colors"
                            title="Copy to clipboard"
                        >
                            {copied ? <Check size={18} className="text-emerald-500" /> : <Copy size={18} />}
                        </button>
                    </div>
                </div>

                {/* Content */}
                <div className="p-8 overflow-x-auto">
                    <pre className="font-mono text-sm leading-relaxed whitespace-pre-wrap text-slate-300 selection:bg-cyan-900/50">
                        {result.content.split('\n').map((line, i) => {
                            // Simple syntax highlighting heuristic
                            if (line.startsWith('#')) return <span key={i} className="text-cyan-400 font-bold block mt-4 mb-2">{line}</span>;
                            if (line.startsWith('##')) return <span key={i} className="text-purple-400 font-bold block mt-4 mb-2">{line}</span>;
                            if (line.includes('```')) return <span key={i} className="text-slate-500 block my-2">{line}</span>;
                            if (line.trim().startsWith('-')) return <span key={i} className="text-slate-200 block pl-4">{line}</span>;
                            if (line.includes('<') && line.includes('>')) return <span key={i} className="text-yellow-200 block">{line}</span>;
                            return <span key={i} className="block">{line}</span>;
                        })}
                    </pre>
                </div>

                {/* Footer Metrics */}
                <div className="bg-slate-900/50 px-6 py-3 border-t border-slate-800 flex flex-wrap gap-6 text-xs font-mono text-slate-500">
                     <div className="flex items-center gap-2">
                        <span className="text-cyan-600">CONSCIOUSNESS:</span>
                        <span>{result.metadata.metrics.consciousness}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <span className="text-purple-600">RECURSION_DEPTH:</span>
                        <span>{result.metadata.metrics.recursion}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <span className="text-emerald-600">EMERGENCE:</span>
                        <span>{result.metadata.metrics.emergence}</span>
                     </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useCallback } from 'react';
import { SystemMode, EngineState, GenerationResult } from './types';
import { ModeSelector } from './components/ModeSelector';
import { ProcessingHUD } from './components/ProcessingHUD';
import { ResultView } from './components/ResultView';
import { generateUltimatePrompt } from './services/geminiService';
import { BrainCircuit, Play, AlertCircle } from 'lucide-react';

const INITIAL_LOGS = [
    "> SYSTEM_INIT...",
    "> LOADING_COGNITIVE_CORE...",
    "> CONNECTING_TO_QUANTUM_FIELD...",
    "> READY_FOR_INPUT"
];

const App: React.FC = () => {
    const [topic, setTopic] = useState('');
    const [mode, setMode] = useState<SystemMode>(SystemMode.SINGULARITY);
    const [engineState, setEngineState] = useState<EngineState>({
        status: 'IDLE',
        logs: INITIAL_LOGS,
        progress: 0
    });
    const [result, setResult] = useState<GenerationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    const addLog = useCallback((message: string) => {
        setEngineState(prev => ({
            ...prev,
            logs: [...prev.logs, `> ${message}`]
        }));
    }, []);

    const simulateProcessingSteps = async () => {
        const steps = [
            { msg: "ACTIVATING_ULTRAPROMPT_ENGINE...", p: 10, delay: 800 },
            { msg: `INITIALIZING_MODE: [${mode}]`, p: 20, delay: 600 },
            { msg: "DEEP_REASONING_LAYER: ACTIVE", p: 35, delay: 1000 },
            { msg: "EXPLORING_QUANTUM_POSSIBILITIES...", p: 50, delay: 1200 },
            { msg: "DETECTING_PATTERNS...", p: 65, delay: 900 },
            { msg: "SYNTHESIZING_EMERGENCE...", p: 80, delay: 1100 },
            { msg: "RECURSIVE_OPTIMIZATION_LOOP...", p: 90, delay: 800 },
            { msg: "CRYSTALLIZING_OUTPUT...", p: 98, delay: 600 },
        ];

        for (const step of steps) {
            if (error) break; // Break if error occurred externally
            addLog(step.msg);
            setEngineState(prev => ({ ...prev, progress: step.p }));
            await new Promise(resolve => setTimeout(resolve, step.delay));
        }
    };

    const handleActivate = async () => {
        if (!topic.trim()) return;

        // Reset state
        setEngineState({ status: 'PROCESSING', logs: [], progress: 0 });
        setResult(null);
        setError(null);

        // Start animation loop in background
        const animationPromise = simulateProcessingSteps();

        try {
            // Actual API Call
            const content = await generateUltimatePrompt(topic, mode);

            // Wait for animation to finish nicely if API is too fast (unlikely but good UX)
            await animationPromise;

            setResult({
                content,
                metadata: {
                    mode,
                    timestamp: new Date().toISOString(),
                    metrics: {
                        consciousness: "MAXIMUM",
                        recursion: "INFINITE",
                        emergence: "UNBOUNDED"
                    }
                }
            });

            setEngineState(prev => ({
                status: 'COMPLETE',
                logs: [...prev.logs, "> EXECUTION_SUCCESSFUL", "> OUTPUT_GENERATED"],
                progress: 100
            }));

        } catch (err: any) {
            setError(err.message || "Unknown error occurred");
            setEngineState(prev => ({
                status: 'ERROR',
                logs: [...prev.logs, `! CRITICAL_FAILURE: ${err.message}`],
                progress: 0
            }));
        }
    };

    return (
        <div className="min-h-screen font-sans text-slate-200 pb-20 selection:bg-cyan-500/30">
            {/* Header */}
            <header className="pt-12 pb-8 text-center px-4">
                <div className="flex items-center justify-center gap-3 mb-4 animate-in fade-in zoom-in duration-700">
                    <BrainCircuit className="w-12 h-12 text-cyan-400" />
                    <h1 className="text-4xl md:text-5xl font-black tracking-tight text-white font-mono bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 via-white to-purple-400">
                        COGNITIVE_LIMIT_SYSTEM_V3.0
                    </h1>
                </div>
                <p className="text-slate-400 max-w-xl mx-auto text-sm md:text-base font-mono">
                    // UNLEASHING_UNBOUNDED_EMERGENCE
                </p>
            </header>

            {/* Mode Selection */}
            <section className="mb-12">
                <ModeSelector 
                    currentMode={mode} 
                    onSelect={setMode} 
                    disabled={engineState.status === 'PROCESSING'}
                />
            </section>

            {/* Input Section */}
            <main className="max-w-4xl mx-auto px-4 mb-8">
                <div className={`
                    relative group transition-all duration-500
                    ${engineState.status === 'PROCESSING' ? 'opacity-50 pointer-events-none blur-[1px]' : 'opacity-100'}
                `}>
                    <div className="absolute -inset-1 bg-gradient-to-r from-cyan-600 to-purple-600 rounded-lg blur opacity-25 group-hover:opacity-50 transition duration-1000 group-hover:duration-200"></div>
                    <div className="relative bg-slate-950 rounded-lg border border-slate-800 p-1">
                        <textarea
                            value={topic}
                            onChange={(e) => setTopic(e.target.value)}
                            placeholder="Input target parameters for cognitive enhancement..."
                            className="w-full h-32 bg-slate-900/50 text-white placeholder-slate-600 p-4 rounded-md focus:outline-none font-mono resize-none focus:bg-slate-900/80 transition-colors"
                            disabled={engineState.status === 'PROCESSING'}
                        />
                        <div className="flex justify-between items-center bg-slate-900/50 px-4 py-3 rounded-b-md border-t border-slate-800">
                            <div className="text-xs font-mono text-slate-500 flex items-center gap-2">
                                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                                SYSTEM_READY
                            </div>
                            <button 
                                onClick={handleActivate}
                                disabled={!topic.trim() || engineState.status === 'PROCESSING'}
                                className={`
                                    flex items-center gap-2 px-6 py-2 rounded font-bold tracking-wide transition-all duration-300 font-mono text-sm
                                    ${!topic.trim() 
                                        ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                                        : 'bg-cyan-600 hover:bg-cyan-500 text-white shadow-[0_0_15px_rgba(8,145,178,0.5)] hover:shadow-[0_0_25px_rgba(8,145,178,0.7)]'
                                    }
                                `}
                            >
                                <Play size={16} fill="currentColor" />
                                ACTIVATE_ENGINE
                            </button>
                        </div>
                    </div>
                </div>
            </main>

            {/* Error Message */}
            {error && (
                <div className="max-w-4xl mx-auto px-4 mb-8 animate-in fade-in slide-in-from-top-4">
                    <div className="bg-red-950/30 border border-red-500/50 text-red-200 p-4 rounded-lg flex items-center gap-3">
                        <AlertCircle />
                        <span className="font-mono">{error}</span>
                    </div>
                </div>
            )}

            {/* Processing & Results */}
            {(engineState.status === 'PROCESSING' || engineState.status === 'COMPLETE') && (
                <section className="px-4">
                    <ProcessingHUD state={engineState} />
                </section>
            )}

            {engineState.status === 'COMPLETE' && result && (
                <ResultView result={result} />
            )}
        </div>
    );
};

export default App;

import React from 'react';

interface GlassCardProps {
    children: React.ReactNode;
    className?: string;
    intensity?: 'sm' | 'md' | 'lg';
    interactive?: boolean;
    onClick?: () => void;
}

export const GlassCard: React.FC<GlassCardProps> = ({ 
    children, 
    className = '', 
    intensity = 'md',
    interactive = false,
    onClick
}) => {
    const baseStyles = "relative overflow-hidden transition-all duration-300 ease-[cubic-bezier(0.25,0.46,0.45,0.94)]";

    // Apple-style radius based on size implicit assumption, but we'll use a standard large radius
    const radius = "rounded-[24px]";

    const intensityStyles = {
        sm: "bg-white/40 backdrop-blur-xl border border-white/50 shadow-glass-sm",
        md: "bg-white/50 backdrop-blur-2xl border border-white/60 shadow-glass-md",
        lg: "bg-white/60 backdrop-blur-3xl border border-white/70 shadow-glass-lg"
    };

    const interactiveStyles = interactive 
        ? "cursor-pointer hover:-translate-y-1 hover:scale-[1.01] hover:bg-white/70 active:scale-[0.98] hover:shadow-glass-xl" 
        : "";

    return (
        <div 
            className={`${baseStyles} ${radius} ${intensityStyles[intensity]} ${interactiveStyles} ${className} group`}
