                <div className="mt-2 p-2 bg-black/5 rounded-lg border border-black/5 font-mono text-[10px] text-apple-text/60 truncate h-8 flex items-center">
                    {state.logs.length > 0 ? (
                        <span className="animate-in fade-in slide-in-from-bottom-1">
                            {state.logs[state.logs.length - 1].replace('> ', '')}
                        </span>
                    ) : (
                        <span className="opacity-50">等待指令...</span>
                    )}
                </div>
            </div>
        </GlassCard>
    );
};

import React from 'react';
import { GenerationResult, SystemMode } from '../types';
import { Copy, Check, Sparkles, Command } from 'lucide-react';
import { GlassCard } from './GlassCard';

interface ResultViewProps {
    result: GenerationResult | null;
}

export const ResultView: React.FC<ResultViewProps> = ({ result }) => {
    const [copied, setCopied] = React.useState(false);

    const handleCopy = () => {
        if (result) {
            navigator.clipboard.writeText(result.content);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        }
    };

    // If no result, show empty state placeholder
    if (!result) {
        return (
            <GlassCard className="h-full flex flex-col items-center justify-center text-center p-8" intensity="sm">
                <div className="w-16 h-16 rounded-full bg-gradient-to-tr from-apple-blue/20 to-apple-purple/20 flex items-center justify-center mb-4 animate-float">
                    <Sparkles className="text-apple-blue w-8 h-8" />
                </div>
                <h3 className="text-xl font-bold text-apple-text mb-2 tracking-tight">系统就绪</h3>
                <p className="text-sm text-apple-gray max-w-xs leading-relaxed">
                    请配置引擎参数并启动序列，以生成超越极限的提示词系统。
                </p>
            </GlassCard>
        );
    }

    return (
        <GlassCard className="h-full flex flex-col relative" intensity="lg">
             {/* Decorative Background Icon */}
             <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none">
                <i className="fa-solid fa-quote-right text-9xl"></i>
            </div>

            {/* Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-black/5 bg-white/30 backdrop-blur-md sticky top-0 z-20">
                <div className="flex items-center gap-3">
                    <div className="p-1.5 rounded-lg bg-gradient-to-br from-apple-blue to-apple-purple text-white shadow-lg shadow-apple-blue/30">
                        <Command size={14} />
                    </div>
                    <div>
                        <h2 className="text-sm font-bold text-apple-text tracking-wide">思维结晶</h2>
                        <div className="text-[10px] text-apple-gray font-medium flex items-center gap-1.5">
                            <span className={`w-1.5 h-1.5 rounded-full ${
                                result.metadata.mode === SystemMode.SINGULARITY ? 'bg-apple-blue' :
                                result.metadata.mode === SystemMode.METAMORPHOSIS ? 'bg-apple-purple' : 'bg-green-500'
                            }`}></span>
                            {result.metadata.mode}
                        </div>
                    </div>
                </div>
                <button 
                    onClick={handleCopy}
                    className="p-2 rounded-full hover:bg-black/5 text-apple-gray hover:text-apple-blue transition-all active:scale-90"
                    title="复制到剪贴板"
                >
                    {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-8 custom-scrollbar relative z-10">
                <div className="prose prose-sm prose-slate max-w-none">
                    <pre className="whitespace-pre-wrap font-mono text-sm leading-relaxed text-apple-text/80 font-medium">
                        {result.content.split('\n').map((line, i) => {
                            if (line.startsWith('#')) return <span key={i} className="text-transparent bg-clip-text bg-gradient-to-r from-apple-blue to-apple-purple font-bold text-lg block mt-6 mb-3">{line}</span>;
                            if (line.startsWith('##')) return <span key={i} className="text-apple-text font-bold block mt-4 mb-2">{line}</span>;
                            if (line.includes('```')) return <span key={i} className="text-apple-gray/60 block my-2">{line}</span>;
                            if (line.trim().startsWith('-')) return <span key={i} className="text-apple-text/90 block pl-4 relative before:content-['•'] before:absolute before:left-0 before:text-apple-blue">{line}</span>;
                            if (line.includes('<') && line.includes('>')) return <span key={i} className="text-orange-500 font-semibold block">{line}</span>;
                            return <span key={i} className="block">{line}</span>;
                        })}
                    </pre>
                </div>
            </div>

            {/* Footer Metrics */}
            <div className="px-6 py-3 border-t border-black/5 bg-white/20 text-[10px] font-mono text-apple-gray flex justify-between items-center">
                <span>意识深度: {result.metadata.metrics.consciousness}</span>
                <span>涌现指数: {result.metadata.metrics.emergence}</span>
            </div>
        </GlassCard>
    );
};

import React, { useState, useCallback } from 'react';
import { SystemMode, EngineState, GenerationResult } from './types';
import { generateUltimatePrompt } from './services/geminiService';
import { ProcessingHUD } from './components/ProcessingHUD';
import { ResultView } from './components/ResultView';
import { GlassCard } from './components/GlassCard';
import { Play, Hexagon, Layers, Sparkles, QrCode } from 'lucide-react';
import { MODE_DESCRIPTIONS } from './constants';

const INITIAL_LOGS = [
    "> 系统初始化...",
    "> 加载认知核心...",
    "> 连接量子场...",
    "> 等待输入"
];

const App: React.FC = () => {
    const [topic, setTopic] = useState('');
    const [mode, setMode] = useState<SystemMode>(SystemMode.SINGULARITY);
    const [engineState, setEngineState] = useState<EngineState>({
        status: 'IDLE',
        logs: INITIAL_LOGS,
        progress: 0
    });
    const [result, setResult] = useState<GenerationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    const addLog = useCallback((message: string) => {
        setEngineState(prev => ({
            ...prev,
            logs: [...prev.logs, `> ${message}`]
        }));
    }, []);

    const simulateProcessingSteps = async () => {
        const steps = [
            { msg: "激活超级提示引擎...", p: 10, delay: 800 },
            { msg: `初始化模式: [${mode}]`, p: 20, delay: 600 },
            { msg: "深度推理层: 激活", p: 35, delay: 1000 },
            { msg: "探索量子可能性...", p: 50, delay: 1200 },
            { msg: "识别模式...", p: 65, delay: 900 },
            { msg: "合成涌现...", p: 80, delay: 1100 },
            { msg: "递归优化循环...", p: 90, delay: 800 },
            { msg: "结晶输出...", p: 98, delay: 600 },
        ];

        for (const step of steps) {
            if (error) break;
            addLog(step.msg);
            setEngineState(prev => ({ ...prev, progress: step.p }));
            await new Promise(resolve => setTimeout(resolve, step.delay));
        }
    };

    const handleActivate = async () => {
        if (!topic.trim()) return;
        setEngineState({ status: 'PROCESSING', logs: [], progress: 0 });
        setResult(null);
        setError(null);

        const animationPromise = simulateProcessingSteps();

        try {
            const content = await generateUltimatePrompt(topic, mode);
            await animationPromise;

            setResult({
                content,
                metadata: {
                    mode,
                    timestamp: new Date().toISOString(),
                    metrics: {
                        consciousness: "MAXIMUM",
                        recursion: "INFINITE",
                        emergence: "UNBOUNDED"
                    }
                }
            });

            setEngineState(prev => ({
                status: 'COMPLETE',
                logs: [...prev.logs, "> 执行成功", "> 输出已生成"],
                progress: 100
            }));

        } catch (err: any) {
            setError(err.message || "Unknown error occurred");
            setEngineState(prev => ({
                status: 'ERROR',
                logs: [...prev.logs, `! 严重错误: ${err.message}`],
                progress: 0
            }));
        }
    };

    return (
        <div className="min-h-screen p-4 md:p-8 lg:p-12 flex items-center justify-center">
            <div className="w-full max-w-[1200px] h-full grid grid-cols-1 md:grid-cols-4 md:grid-rows-3 gap-6 auto-rows-[minmax(200px,auto)] md:auto-rows-fr">

                {/* --- GRID AREA A: CORE INTELLIGENCE (MAIN CARD) --- */}
                {/* Spans 2 cols, 2 rows */}
                <GlassCard className="md:col-span-2 md:row-span-2 flex flex-col p-8 md:p-10 relative" intensity="lg">
                    {/* Background Graphic */}
                    <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none transform translate-x-10 -translate-y-10">
                        <i className="fa-solid fa-brain text-[12rem] text-apple-blue"></i>
                    </div>

                    <div className="relative z-10 flex flex-col h-full">
                        <div className="mb-6">
                            <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight text-apple-text mb-2 bg-clip-text text-transparent bg-gradient-to-r from-apple-text to-apple-gray font-sc">
                                认知极限系统
                            </h1>
                            <div className="flex items-center gap-2">
                                <span className="px-2 py-0.5 rounded-full bg-apple-blue/10 text-apple-blue text-[10px] font-bold tracking-wider border border-apple-blue/20">V3.0 测试版</span>
                                <span className="text-apple-gray text-sm font-medium">释放无限涌现力</span>
                            </div>
                        </div>

                        <textarea
                            value={topic}
                            onChange={(e) => setTopic(e.target.value)}
                            placeholder="在此输入您希望突破的认知领域或具体目标..."
                            className="flex-1 w-full bg-white/40 border border-white/50 rounded-2xl p-6 text-apple-text placeholder-apple-gray/60 focus:outline-none focus:ring-2 focus:ring-apple-blue/30 focus:bg-white/60 transition-all resize-none text-lg leading-relaxed mb-6 shadow-inner-light"
                            disabled={engineState.status === 'PROCESSING'}
                        />

                        <button 
                            onClick={handleActivate}
                            disabled={!topic.trim() || engineState.status === 'PROCESSING'}
                            className={`
                                group relative w-full py-4 rounded-xl font-bold tracking-wide transition-all duration-300 overflow-hidden shadow-lg
                                ${!topic.trim() || engineState.status === 'PROCESSING'
                                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                                    : 'bg-apple-text text-white hover:shadow-xl active:scale-[0.98]'
                                }
                            `}
                        >
                             <div className="absolute inset-0 bg-gradient-to-r from-apple-blue to-apple-purple opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                             <div className="relative z-10 flex items-center justify-center gap-2">
                                {engineState.status === 'PROCESSING' ? (
                                    <span className="animate-pulse">正在运算...</span>
                                ) : (
                                    <>
                                        <Play size={18} fill="currentColor" />
                                        <span>激活认知引擎</span>
                                    </>
                                )}
                             </div>
                        </button>
                    </div>
                </GlassCard>

                {/* --- GRID AREA B: MODE - SINGULARITY --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.SINGULARITY)}
                    className={`md:col-span-1 md:row-span-1 p-6 flex flex-col justify-between ${mode === SystemMode.SINGULARITY ? 'ring-2 ring-apple-blue ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                    <div className="flex justify-between items-start">
                         <div className={`p-3 rounded-2xl ${mode === SystemMode.SINGULARITY ? 'bg-apple-blue text-white shadow-lg shadow-apple-blue/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Hexagon size={24} />
                        </div>
                        {mode === SystemMode.SINGULARITY && <div className="w-2 h-2 rounded-full bg-apple-blue animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-lg text-apple-text mb-1">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].label}</h3>
                        <p className="text-xs text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.SINGULARITY].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA C: MODE - METAMORPHOSIS --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.METAMORPHOSIS)}
                    className={`md:col-span-1 md:row-span-1 p-6 flex flex-col justify-between ${mode === SystemMode.METAMORPHOSIS ? 'ring-2 ring-apple-purple ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start">
                         <div className={`p-3 rounded-2xl ${mode === SystemMode.METAMORPHOSIS ? 'bg-apple-purple text-white shadow-lg shadow-apple-purple/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Layers size={24} />
                        </div>
                        {mode === SystemMode.METAMORPHOSIS && <div className="w-2 h-2 rounded-full bg-apple-purple animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-lg text-apple-text mb-1">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].label}</h3>
                        <p className="text-xs text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.METAMORPHOSIS].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA D: MODE - ZENITH --- */}
                <GlassCard 
                    interactive={engineState.status !== 'PROCESSING'}
                    onClick={() => setMode(SystemMode.ZENITH)}
                    className={`md:col-span-1 md:row-span-1 p-6 flex flex-col justify-between ${mode === SystemMode.ZENITH ? 'ring-2 ring-green-500 ring-offset-2 ring-offset-[#F2F2F7]' : 'opacity-70 hover:opacity-100'}`}
                >
                     <div className="flex justify-between items-start">
                         <div className={`p-3 rounded-2xl ${mode === SystemMode.ZENITH ? 'bg-green-500 text-white shadow-lg shadow-green-500/30' : 'bg-white/50 text-apple-gray'}`}>
                            <Sparkles size={24} />
                        </div>
                        {mode === SystemMode.ZENITH && <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>}
                    </div>
                    <div>
                        <h3 className="font-bold text-lg text-apple-text mb-1">{MODE_DESCRIPTIONS[SystemMode.ZENITH].label}</h3>
                        <p className="text-xs text-apple-gray leading-tight line-clamp-2">{MODE_DESCRIPTIONS[SystemMode.ZENITH].desc}</p>
                    </div>
                </GlassCard>

                {/* --- GRID AREA E: HUD --- */}
                <div className="md:col-span-1 md:row-span-1">
                    <ProcessingHUD state={engineState} />
                </div>

                {/* --- GRID AREA F: OUTPUT --- */}
                <div className="md:col-span-3 md:row-span-1 h-full min-h-[300px]">
                    <ResultView result={result} />
                </div>

                {/* --- GRID AREA G: BRAND / QR --- */}
                <GlassCard className="md:col-span-1 md:row-span-1 flex flex-col items-center justify-center p-6 text-center" intensity="sm">
                    <div className="w-24 h-24 bg-white/80 rounded-xl p-2 shadow-inner mb-4 flex items-center justify-center">
                         <QrCode className="w-full h-full text-apple-text" strokeWidth={1.5} />
                    </div>
                    <div className="text-apple-text font-bold text-sm tracking-tight">认知系统</div>
                    <div className="text-apple-gray text-[10px] mt-1 font-mono">扫码体验</div>
                </GlassCard>

            </div>
        </div>
    );
};

